@startuml
title Drupal 7 Commerce Entity Controller Class Inheritance

package "Entity Module" {
  class EntityApiController {
    <<controller>>
    EntityApiController
  }
  class DrupalDefaultEntityController {
    <<controller>>
    DrupalDefaultEntityController
  }
  EntityApiController --|> DrupalDefaultEntityController
}

package "Commerce Module" {
  class DrupalCommerceEntityController {
    <<controller>>
    DrupalCommerceEntityController
  }
  class CommerceCustomerProfileEntityController {
    <<controller>>
    CommerceCustomerProfileEntityController
  }
  class CommerceLineItemEntityController {
    <<controller>>
    CommerceLineItemEntityController
  }
  class CommercePaymentTransactionEntityController {
    <<controller>>
    CommercePaymentTransactionEntityController
  }
  class CommerceProductEntityController {
    <<controller>>
    CommerceProductEntityController
  }
  class CommerceOrderEntityController {
    <<controller>>
    CommerceOrderEntityController
  }
  DrupalCommerceEntityController --|> DrupalDefaultEntityController
  CommerceCustomerProfileEntityController --|> DrupalCommerceEntityController
  CommerceLineItemEntityController --|> DrupalCommerceEntityController
  CommercePaymentTransactionEntityController --|> DrupalCommerceEntityController
  CommerceProductEntityController --|> DrupalCommerceEntityController
  CommerceOrderEntityController --|> DrupalCommerceEntityController
}

@enduml
